bloecke.simulation:
const sp = Speicher(0x08F2);

sp.int("n", 5);
sp.ptr("p", "n");
sp.tabelle("int n = 5;  int *p = &n;");

sp.deref("p", 10);
sp.tabelle("nach  *p = 10;   (n wurde über den Zeiger geändert!)");

sp.inc("p");
sp.tabelle("nach  p++;   (Adresse in p ist um 2 Byte gesprungen)");

console.log("n =", sp.wert("n"), "— geändert, ohne n direkt anzufassen!");
